const { Telegraf } = require('telegraf');
const axios = require('axios');
const cron = require('node-cron');

// ═══════════════════════════════════════════════════════════
// CONFIGURATION
// ═══════════════════════════════════════════════════════════

const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const PRIVATE_CHANNEL = process.env.PRIVATE_CHANNEL || '-1001111111111'; // Admin bunker
const PUBLIC_CHANNEL = process.env.PUBLIC_CHANNEL || '-1002222222222';   // Community alerts
const ADMIN_IDS = (process.env.ADMIN_IDS || '').split(',').map(id => parseInt(id.trim())).filter(Boolean);

const OLLAMA_URL = process.env.OLLAMA_URL || 'http://127.0.0.1:11434/api/generate';
const DEFAULT_MODEL = process.env.DEFAULT_MODEL || 'gemma2:9b';

const SCYLLA_HOSTS = (process.env.SCYLLA_HOSTS || '127.0.0.1').split(',');

// ═══════════════════════════════════════════════════════════
// UTILITIES
// ═══════════════════════════════════════════════════════════

/**
 * Truncate wallet address for public display
 */
function truncateWallet(address, visible = 6) {
  if (!address || address.length < visible * 2 + 4) return address;
  return `${address.slice(0, visible)}...${address.slice(-visible)}`;
}

/**
 * Get risk emoji based on score
 */
function getRiskEmoji(score) {
  if (score >= 80) return '🚨';
  if (score >= 60) return '⚠️';
  if (score >= 40) return '⚡';
  return '✅';
}

/**
 * Check if user is admin
 */
function isAdmin(userId) {
  return ADMIN_IDS.includes(userId);
}

// ═══════════════════════════════════════════════════════════
// DUAL-CHANNEL ALERT FORMATTERS
// ═══════════════════════════════════════════════════════════

/**
 * Format FULL alert for private admin channel
 */
function formatPrivateAlert(scan) {
  const emoji = getRiskEmoji(scan.risk_score);

  let message = `
${emoji} <b>RUGMUNCHBOT ALERT - ${scan.threat_level.toUpperCase()}</b>

<b>Contract:</b> <code>${scan.contract_address}</code>
<b>Chain:</b> ${scan.chain.toUpperCase()}
<b>Risk Score:</b> <code>${scan.risk_score}/100</b>

<b>🔍 FINDINGS:</b>`;

  // Add findings with full details
  for (const finding of (scan.findings || []).slice(0, 10)) {
    const severityEmoji = {
      'critical': '🔴',
      'high': '🟠',
      'medium': '🟡',
      'low': '🔵'
    }[finding.severity] || '⚪';

    message += `\n${severityEmoji} <b>${finding.title || 'Issue'}</b>`;
    message += `\n   ${finding.description || 'No details'}`;

    if (finding.wallet) {
      message += `\n   Wallet: <code>${finding.wallet}</code>`;
    }
    if (finding.tx_hash) {
      message += `\n   TX: <code>${finding.tx_hash}</code>`;
    }
  }

  // Include holder data if available
  if (scan.holder_data && scan.holder_data.length > 0) {
    message += `\n\n<b>👥 TOP HOLDERS:</b>`;
    for (const holder of scan.holder_data.slice(0, 5)) {
      message += `\n  <code>${holder.address}</code>: ${holder.percentage}%`;
    }
  }

  message += `\n\n<i>Full analysis via /analyze ${scan.contract_address}</i>`;

  return message;
}

/**
 * Format SANITIZED alert for public channel
 */
function formatPublicAlert(scan) {
  const emoji = getRiskEmoji(scan.risk_score);
  const truncatedAddr = truncateWallet(scan.contract_address);

  let message = `
${emoji} <b>RUGMUNCHBOT ALERT</b>

<b>Token:</b> <code>${truncatedAddr}</code>
<b>Chain:</b> ${scan.chain.toUpperCase()}
<b>Risk Score:</b> <code>${scan.risk_score}/100</b> - ${scan.threat_level.toUpperCase()}`;

  // Sanitized findings summary
  if (scan.findings && scan.findings.length > 0) {
    const criticalCount = scan.findings.filter(f => f.severity === 'critical').length;
    const highCount = scan.findings.filter(f => f.severity === 'high').length;

    if (criticalCount > 0) {
      message += `\n⚠️ <b>${criticalCount} Critical</b> issues detected`;
    }
    if (highCount > 0) {
      message += `\n⚡ <b>${highCount} High Risk</b> issues detected`;
    }
  }

